## [Tree](http://acm.hdu.edu.cn/showproblem.php?pid=6547)

&nbsp;

**树链刨分+线段树**

当线段树到叶节点时更新节点，当区间和为1时不再更新这个区间。

```c++

#include<bits/stdc++.h>
#define int long long
using namespace std;
const int maxn=1e5+10;
struct edge{
    int next,to;
}e[maxn*2];
struct node{
    int l,r,ls,rs,sum,lazy;
    int flag;
}a[maxn*2];
int n,m,r,rt,v[maxn],head[maxn],cnt,f[maxn],d[maxn],son[maxn],size[maxn],top[maxn],id[maxn],rk[maxn];
void add(int x,int y)
{
    e[++cnt].next=head[x];
    e[cnt].to=y;
    head[x]=cnt;
}
void dfs1(int x)
{

    size[x]=1,d[x]=d[f[x]]+1;
    for(int v,i=head[x];i;i=e[i].next)
        if((v=e[i].to)!=f[x])
        {
            f[v]=x,dfs1(v),size[x]+=size[v];
            if(size[son[x]]<size[v])
                son[x]=v;
        }
}
void dfs2(int x,int tp)
{

    top[x]=tp,id[x]=++cnt,rk[cnt]=x;
    if(son[x])
        dfs2(son[x],tp);
    for(int v,i=head[x];i;i=e[i].next)
        if((v=e[i].to)!=f[x]&&v!=son[x])
            dfs2(v,v);
}
inline void pushup(int x)
{
    a[x].sum=(a[a[x].ls].sum+a[a[x].rs].sum);
    a[x].flag=(a[a[x].ls].flag&a[a[x].rs].flag);
}
void build(int l,int r,int x)
{

    //cout<<l<<" "<<r<<endl;
    a[x].flag=0;
    if(l==r)
    {

        a[x].sum=v[rk[l]],a[x].l=a[x].r=l;
        if(a[x].sum==1) a[x].flag=1;
        return;
    }
    int mid=l+r>>1;
    a[x].ls=cnt++,a[x].rs=cnt++;
    build(l,mid,a[x].ls),build(mid+1,r,a[x].rs);
    a[x].l=a[a[x].ls].l,a[x].r=a[a[x].rs].r;
    pushup(x);
}
inline int len(int x)
{
    return a[x].r-a[x].l+1;
}
inline void pushdown(int x)
{
    if(a[x].lazy)
    {
        int ls=a[x].ls,rs=a[x].rs,lz=a[x].lazy;
        (a[ls].lazy+=lz),(a[rs].lazy+=lz);
        (a[ls].sum+=lz*len(ls)),(a[rs].sum+=lz*len(rs));
        a[x].lazy=0;
    }
}
void update(int l,int r,int x)
{
    if(a[x].l>=l&&a[x].r<=r)
    {
       if(a[x].flag==1)
        return;
    }
    if(a[x].l==a[x].r) 
    {
        a[x].sum=sqrt(a[x].sum);
        if(a[x].sum==1) a[x].flag=1;
        return ;
    }
    int mid=a[x].l+a[x].r>>1;
    if(mid>=l)
        update(l,r,a[x].ls);
    if(mid<r)
        update(l,r,a[x].rs);
    pushup(x);
}
int query(int l,int r,int x)
{
    if(a[x].l>=l&&a[x].r<=r)
        return a[x].sum;
    pushdown(x);
    int mid=a[x].l+a[x].r>>1,tot=0;
    if(mid>=l)
        tot+=query(l,r,a[x].ls);
    if(mid<r)
        tot+=query(l,r,a[x].rs);
    return tot;
}
inline int sum(int x,int y)
{
    int ret=0;
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
            swap(x,y);
        (ret+=query(id[top[x]],id[x],rt));
        x=f[top[x]];
    }
    if(id[x]>id[y])
        swap(x,y);
    return (ret+query(id[x],id[y],rt));
}
inline void updates(int x,int y)
{
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
            swap(x,y);
        update(id[top[x]],id[x],rt);
        x=f[top[x]];
    }
    if(id[x]>id[y])
        swap(x,y);
    update(id[x],id[y],rt);
}
signed main()
{
    scanf("%lld%lld",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%lld",&v[i]);
    for(int x,y,i=1;i<n;i++)
    {
        scanf("%lld%lld",&x,&y);
        add(x,y),add(y,x);
    }
    r=1;
    cnt=0,dfs1(r),dfs2(r,r);
    cnt=0,build(1,n,rt=cnt++);
   // cout<<111<<endl;
    for(int op,x,y,k,i=1;i<=m;i++)
    {
        scanf("%lld",&op);
        if(op==0)
        {
            k=0;
            scanf("%lld%lld",&x,&y);
            updates(x,y);
        }
        else if(op==1)
        {
            scanf("%lld%lld",&x,&y);
            printf("%lld\n",sum(x,y));
        }  
        /*for(int z=1;z<=n;z++)
            cout<<sum(z,z)<<"# "; */
    }
    return 0;
}
```

