//	cout<<"qi"<<qi<<endl;

	int n1=1;
	for(int i=1;i<=n;i++)
	{
		int a,b,c;
		sd(a);sd(b);sd(c);
		a=tn(a);
		dian[n1].a=a;dian[n1].b=b;dian[n1].c=c;
		int zz=tim(a,b,c);

//		cout<<"zz"<<zz<<endl;

		int kk=zz-qi;
//		cout<<"kk"<<kk<<endl;

		if(kk<0)
		{
			dian[n1].ni=abs(kk);
			dian[n1].shun=43200-dian[n1].ni;
			n1++;
		}
		else
		{
			if(kk>0)
			{
				dian[n1].shun=kk;
		//		cout<<"kk>0"<<endl;
			dian[n1].ni=43200-dian[i].shun;
