## A. Password

&nbsp;

**KMP模板题**

唯一需要注意的是KMP求得的是最大前缀后缀长度，而本题需要任意长度的公共前缀后缀，不过根据KMP的思想，递归next数组就可以了。

```c++
#include<iostream>
#include<string>
#include<cstring>
using namespace std;
const int maxn = 1e6 + 5;
#define ll long long
int nxt[maxn];
void getNextVal(string p) {
	int plen = p.length();
	nxt[0] = -1;
	int k = -1;
	int j = 0;
	while (j < plen) {
		if (k == -1 || p[j] == p[k]) {
			j++;
			k++;
			if (p[j] != p[k]) {
				nxt[j] = k;
			}
			else{
				nxt[j] = nxt[k];
			}
		}
		else { 
			k = nxt[k];
		}
	}
}
int kmp(string s, string p) {
	int i = 0, j = 0;
	getNextVal(p);
	int slen = s.length();
	int plen = p.length();
	while (i < slen&&j < plen) {
		if (j == -1 || s[i] == p[j]) {
			i++;
			j++;
		}
		else {
			j = nxt[j];
		}
	}
	if (j == plen) {
		return i - j;
	}
	else {
		return -1;
	}
}
int main() {
	string s;
	cin >> s;
	getNextVal(s);
	int len = s.length();
	int k = nxt[len];
	while (k != 0) {
		string p = s.substr(0, k);
		string s1 = s.substr(1,len-2);
		if (kmp(s1, p) != -1) {
			cout << p;
			return 0;
		}
		k = nxt[k];
	}
	cout << "Just a legend";
	return 0;
}
```

