## D. Little Elephant and Interval

&nbsp;

**枚举**，找到[l，r]区间中第一位和最后一位相等的数的个数。

solve(x)函数确定[ 0 , x ]区间中满足条件的数个数，之后solve(r)-solve(l-1)。

```c++
#include<iostream>
#include<algorithm>
#include<string>
using namespace std;
#define ll long long
const ll maxn = 1e18 + 5;
ll l, r;
ll ans;
int get_dig(ll a) {
	int ans = 1;
	while (a / 10) {
		ans++;
		a /= 10;
	}
	return ans;
}
ll pow(int n) {
	ll ans = 1;
	for (int i = 0; i < n; i++)
		ans *= 10;
	return ans;
}
ll solve(ll x) {
	int n = get_dig(x);
	ll ans = 10;
	ll t = 9;
	if (x < 10) {
		return x+1 ;
	}
	for (int i = 0; i < n - 2;i++) {
		ans += t;
		t *= 10;
	}
	int l = x / pow(n - 1);
	int r = x % 10;
	if (l <= r)ans++;
	x /= 10;
	x -= pow(n - 2);
	return ans + x;
}
int main() {
	cin >> l >> r;
	cout << (solve(r) - solve(l-1));
	return 0;
}
```

