给定一棵树，找到它的重心，重心上填上最高级的officer，再对它的子树递归。

```c++
#include<iostream>
#include<string>
#include<cstring>
#include<vector>
#include<algorithm>
using namespace std;
const int maxn = 1e5 + 5;
#define ll long long
int n;
vector<int>G[maxn];
void add_edge(int u, int v) {
	G[u].push_back(v);
	G[v].push_back(u);
}
int root;
int Siz;
int mxsz[maxn], sz[maxn], ans[maxn];
bool vis[maxn];
void get_rt(int u,int fa) {
	mxsz[u] = 0;
	sz[u] = 1;
	for (int i = 0; i < G[u].size(); i++) {
		int v = G[u][i];
		if (!vis[v] && v != fa) {
			get_rt(v, u);
			sz[u] += sz[v];
			mxsz[u] = max(mxsz[u], sz[v]);
		}
	}
	mxsz[u] = max(mxsz[u], Siz - sz[u]);
	if (mxsz[u] <= mxsz[root])root = u;
}
void dfs(int rt,int dep) {
	ans[rt] = dep;
	vis[rt] = 1;
	for (int i = 0; i < G[rt].size(); i++) {
		int v = G[rt][i];
		if (!vis[v]) {
			root = 0;
			Siz = sz[v];
			get_rt(v, rt);
			dfs(root, dep + 1);
		}
	}
}
int main() {
	cin.sync_with_stdio(false);
	cin >> n;
	for (int i = 0; i < n - 1; i++) {
