后来查了一下，要用并查集，当当前盆p满了，就把它和下面的盆p+1合并。

**注意，由于一定是往下合并，所以不能用rank数组优化。**

```c++
#include<iostream>
#include<algorithm>
#include<cstring>
#include<vector>
#include<string>
using namespace std;
#define ll long long
const int maxn = 2e5 + 5;
int n, m;
int par[maxn];
int rak[maxn];
ll a[maxn];
ll b[maxn];
void init(int n) {
	for (int i = 1; i <= n; i++) {
		par[i] = i;
	}
}
int find(int x) {
	if (par[x] == x) {
		return x;
	}
	else {
		return par[x] = find(par[x]);
	}
}
void unit(int x, int y) {
	y = find(y);
	par[x] = find(y);
}
bool same(int x, int y) {
	return find(x) == find(y);
}
int main() {
	cin.sync_with_stdio(false);
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
	}
	init(n);
	cin >> m;
	for (int i = 0; i < m; i++) {
		int instr;
		cin >> instr;
		if (instr == 1) {
			int p, x;
			cin >> p >> x;
			while (x > 0) {
				int pf = find(p);
				if (x < a[pf] - b[pf]) {
					b[pf] += x;
					x = 0;
				}
				else {
					x -= (a[pf] - b[pf]);
					b[pf] = a[pf];
					if (same(n, pf)) {
						x = 0;
					}
					else {
						unit(pf, pf + 1);
						pf = find(pf + 1);
					}
				}
			}
		}
		else {
			int k;
			cin >> k;
			cout << b[k] << endl;
		}
	}
	return 0;
}
