**找规律，分类讨论**

把相邻的能合成9的数合成9，要求9最多的方案数。

如果奇数个能合成9，例如363，则有两种方案，合成39或93，ans*2；若偶数个，如3636，则必须全部合成9，只有1种.

```c++
#include<iostream>
#include<algorithm>
#include<cstring>
#include<string>
using namespace std;
#define ll long long
int main() {
	string s;
	cin >> s;
	ll cnt = 1;
	ll ans = 1;
	for (int i = 1; i <= s.length(); i++) {
		if (i == s.length() || (s[i] + s[i - 1] - 2 * '0' != 9)) {
			if (cnt > 1 && (cnt & 1)) {
				ans *= (cnt + 1)/2;
			}
			cnt = 1;
		}
		else {
			cnt++;
		}
	}
	cout << ans;
	return 0;
}
