  代码：

```c++
#include<algorithm>
#include<iostream>
#include<queue>
#include<cstring>
using namespace std;
#define ll long long
typedef pair<ll, int> pii;
const ll INF = 1LL << 62;
int n, m;
ll k;
bool is_big[1005];
struct Edge
{
	int to;
	ll cost;
	Edge(int t,ll c):to(t),cost(c){}
};
vector<Edge>G[1005], gg[1005];
ll d[1005];
ll g[1005][1005];
void add_edge(int u, int v, int w) {
	G[u].push_back(Edge{ v,w });
	G[v].push_back(Edge{ u,w });
}
void Dij1(int s) {
	priority_queue<pii, vector<pii>, greater<pii> >que;
	g[s][s] = 0;
	que.push(pii(0ll, s));
	while (!que.empty()) {
		pii tp = que.top();
		que.pop();
		int id = tp.second;
		for (int i = 0; i < G[id].size(); i++) {
			Edge e = G[id][i];
			if (g[s][e.to] > g[s][id] + e.cost) {
				g[e.to][s]=g[s][e.to] = g[s][id] + e.cost;
				if(!is_big[e.to])
					que.push(pii(g[s][e.to], e.to));
			}
		}
	}
}
void rebuild() {
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= n; j++) {
			if ((!is_big[i]) || (!is_big[j]))continue;
			if (i != j && g[i][j] <= k)
				gg[i].push_back(Edge{ j,g[i][j] });
		}
	}
}
void solve() {
	memset(d, 0x3f, sizeof(d));
	priority_queue<pii, vector<pii>, greater<pii> >que;
	que.push(pii(0ll, 1));
	d[1] = 0;
	while (!que.empty()) {
		pii tp = que.top();
		que.pop();
		int id = tp.second;
		for (int i = 0; i < gg[id].size(); i++) {
			Edge e = gg[id][i];
			if (d[e.to] > d[id] + e.cost) {
				d[e.to] = d[id] + e.cost;
				que.push(pii(d[e.to], e.to));
			}
		}
	}
	cout << d[n];
}
int main() {
	cin.sync_with_stdio(false);
	cin >> n >> m >> k;
	for (int i = 1; i <= n; i++) {
		cin >> is_big[i];
	}
	for (int i = 1; i <= m; i++) {
		int u, v, w;
		cin >> u >> v >> w;
		add_edge(u, v, w);
	}
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= n; j++)
			g[i][j] = INF;
	}
	for (int i = 1; i <= n ; i++) {
		if(is_big[i])
			Dij1(i);
	}
	rebuild();
	solve();
	return 0;
}
```

