## C. Jzzhu and Cities

&nbsp;

Dijkstra

把所有（包含train路）的边存图，以1为起点存每个点的最短路。

对一个train，如果它的长度大于该点的最短路，直接删除；若等于最短路，如果最短路不止一条，删除。

```c++
#include<iostream>
#include<queue>
#include<algorithm>
#include<cstring>
#include<map>
#include<functional>
using namespace std;
#define ll long long
int n, m, k;
const int maxn = 1e5 + 200;
typedef pair<long, int> pii;
struct node {
	int to;
	int dis;
};
vector<node>G[maxn];
ll d[maxn];
bool vis[maxn];
void add_edge(int u, int v, int x) {
	G[u].push_back(node{ v,x });
	G[v].push_back(node{ u,x });
}
int s[maxn];
ll y[maxn];
priority_queue<pii, vector<pii>, greater<pii> >que;
int in[maxn];
void dij() {
	que.push(pii(0ll,1));
	while (!que.empty()) {
		pii tp = que.top();
		que.pop();
		int u = tp.second;
		if (vis[u])continue;
		vis[u] = 1;
		for (int i = 0; i < G[u].size(); i++) {
			int v = G[u][i].to, dis = G[u][i].dis;
			if (d[u] + dis < d[v]) {
				in[v] = 1;
				d[v] = d[u] + dis;
				que.push(pii(d[v],v));
			}
			else if (d[u] + dis == d[v])
				in[v]++;
		}
	}
}
int main() {
	cin.sync_with_stdio(false);
	memset(d, 0x3f, sizeof(d));
	cin >> n >> m >> k;
	for (int i = 0; i < m; i++) {
		int u, v, x;
		cin >> u >> v >> x;
		add_edge(u, v, x);
	}
	for (int i = 0; i < k; i++) {
		cin >> s[i] >> y[i];
		add_edge(1, s[i], y[i]);
	}
	d[1] = 0;
	dij();
	//cout << d[0];
	int ans = 0;
	for (int i = 0; i < k; i++) {
		if (y[i] > d[s[i]])ans++;
		else {
			if (d[s[i]]==y[i]&&in[s[i]] > 1) {
				ans++;
				in[s[i]]--;
			}
		}
	}
	cout << ans;
	return 0;
}
```

