## C. Split a Number

&nbsp;

用大数模板就过了，分奇偶讨论，偶数时从中间找到两边不为零的位置，作为后半部分的开头数字，比较两种的大小；奇数时分中间是否为零，不为零则mid和mid+1作为后半部分开头，比较大小，为零则类似偶数。

```c++
#include <bits/stdc++.h>
using namespace std;
 
struct BigInteger
{
	static const int BASE = 100000000; 
	static const int WIDTH = 8;       
	bool sign;                       
	size_t length;                   
	vector<int> num;                 

	BigInteger(long long x = 0) { *this = x; }
	BigInteger(const string &x) { *this = x; }
	BigInteger(const BigInteger &x) { *this = x; }
	BigInteger &operator=(long long x)
	{
		num.clear();
		if (x >= 0)
		{
			sign = true;
		}
		else
		{
			sign = false;
			x = -x;
		}
		do
		{
			num.push_back(x % BASE);
			x /= BASE;
		} while (x > 0);
		cutLeadingZero();
		return *this;
	}
	BigInteger &operator=(const string &str)
	{
		num.clear();
		sign = (str[0] != '-');
		int x, len = (str.size() - 1 - (!sign)) / WIDTH + 1;
		for (int i = 0; i < len; i++)
		{
			int End = str.size() - i * WIDTH;
			int start = max((int)(!sign), End - WIDTH);
			sscanf(str.substr(start, End - start).c_str(), "%d", &x);
			num.push_back(x);
		}
		cutLeadingZero();
		return *this;
	}
	BigInteger &operator=(const BigInteger &tmp)
	{
		num = tmp.num;
		sign = tmp.sign;
		length = tmp.length;
		return *this;
	}
	const BigInteger &operator+() const { return *this; }
	BigInteger operator+(const BigInteger &b) const
	{
		if (!b.sign)
		{
			return *this - (-b);
		}
		if (!sign)
		{
			return b - (-*this);
		}
		BigInteger ans;
		ans.num.clear();
		for (int i = 0, g = 0;; i++)
		{
			if (g == 0 && i >= num.size() && i >= b.num.size())
				break;
			int x = g;
			if (i < num.size())
				x += num[i];
			if (i < b.num.size())
				x += b.num[i];
			ans.num.push_back(x % BASE);
			g = x / BASE;
		}
		ans.cutLeadingZero();
		return ans;
	}

	BigInteger &operator+=(const BigInteger &b)
	{
		*this = *this + b;
		return *this;
	}

	bool operator<(const BigInteger &b) const
	{
		if (sign != b.sign)
		{
			return !sign;
		}
		else if (!sign && !b.sign)
		{
			return -b < -*this;
		}
		if (num.size() != b.num.size())
			return num.size() < b.num.size();
		for (int i = num.size() - 1; i >= 0; i--)
			if (num[i] != b.num[i])
				return num[i] < b.num[i];
		return false;
	}
	bool operator>(const BigInteger &b) const { return b < *this; } 
	bool operator<=(const BigInteger &b) const { return !(b < *this); }
	bool operator>=(const BigInteger &b) const { return !(*this < b); } 
	bool operator!=(const BigInteger &b) const { return b < *this || *this < b; } 
	bool operator==(const BigInteger &b) const { return !(b < *this) && !(*this < b); }
	friend ostream &operator<<(ostream &out, const BigInteger &x)
	{
		if (!x.sign)
			out << '-';
		out << x.num.back();
		for (int i = x.num.size() - 2; i >= 0; i--)
		{
			char buf[10];
			sprintf(buf, "%08d", x.num[i]);
			for (int j = 0; j < strlen(buf); j++)
				out << buf[j];
		}
		return out;
	}
	friend istream &operator>>(istream &in, BigInteger &x)
	{
		string str;
		in >> str;
		size_t len = str.size();
		int start = 0;
		if (str[0] == '-')
			start = 1;
		if (str[start] == '\0')
			return in;
		for (int i = start; i < len; i++)
		{
			if (str[i] < '0' || str[i] > '9')
				return in;
		}
		x.sign = !start;
		x = str.c_str();
		return in;
	}
};
 
int main()
{	
	int l;
	cin >> l;
	string s;
	cin >> s;
	if (l % 2 == 0) {
		int md = l / 2;
		int md1 = md, md2 = md;
		while (s[md1] == '0'&&md1 > 0) {
			md1--;
		}
		while (s[md2] == '0'&&md2 < l - 1) {
			md2++;
		}
		if (md1 == 0) {
			BigInteger ans2 = BigInteger{ s.substr(0,md2) }+BigInteger{ s.substr(md2) };
			cout << ans2;
		}
		else if (md2 == l - 1) {
			BigInteger ans1 = BigInteger{ s.substr(0,md1) }+BigInteger{ s.substr(md1) };
			cout << ans1;
		}
		else {
			BigInteger ans1 = BigInteger{ s.substr(0,md1) }+BigInteger{ s.substr(md1) };
			BigInteger ans2 = BigInteger{ s.substr(0,md2) }+BigInteger{ s.substr(md2) };
			cout << min(ans1, ans2);
		}
	}
	else {
		int md = l / 2;
		if (s[md] != '0') {
			BigInteger ans1 = BigInteger{ s.substr(0,md) }+BigInteger{ s.substr(md) };
			if (s[md + 1] != 0) {
				ans1 = min(ans1, BigInteger{ s.substr(0,md + 1) }+BigInteger{ s.substr(md + 1) });
			}
			cout << ans1;
		}
		else {
			int md1 = md, md2 = md;
			while (s[md1] == '0'&&md1 > 0) {
				md1--;
			}
			while (s[md2] == '0'&&md2 < l - 1) {
				md2++;
			}
			if (md1 == 0) {
				BigInteger ans2 = BigInteger{ s.substr(0,md2) }+BigInteger{ s.substr(md2) };
				cout << ans2;
			}
			else if (md2 == l - 1) {
				BigInteger ans1 = BigInteger{ s.substr(0,md1) }+BigInteger{ s.substr(md1) };
				cout << ans1;
			}
			else {
				BigInteger ans1 = BigInteger{ s.substr(0,md1) }+BigInteger{ s.substr(md1) };
				BigInteger ans2 = BigInteger{ s.substr(0,md2) }+BigInteger{ s.substr(md2) };
				cout << min(ans1, ans2);
