## F. Vus the Cossack and Numbers

&nbsp;

先对每个数只取整数部分，即正数向下取整，负数向上取整，只需要取int就可做到。同时记录舍去的小数部分，由于所有数的整数部分+小数部分=0，所以小数部分的和一定是整数，讨论该和的正负，由于正数向下取整，因此每个正数都有+1的空间，变为原数向上取整，所以若小数和为正数，则平分到正数上；同理，负数则平分到负数上。

存在精度问题及对0的处理问题。

```c++
#include<iostream>
#include<vector>
#include<cmath>
#include<algorithm>
using namespace std;
typedef pair<int, int> pii;
int n;
double rest;
double a[100005];
vector<int>vc;
bool cmp(int a, int b) {
	return a > b;
}
int main() {
	cin >> n;
	for (int i = 0; i < n; i++) {
		double tp;
		cin >> tp;
		a[i] = tp;
		int ac = tp;
		vc.push_back(tp);
		rest += (tp - ac);
	}
	if (fabs(rest) < 1e-6)rest = 0;
	if (rest > 0) {
		for (int i = 0; i < n; i++) {
			if (a[i] > 0&&((int)a[i]-a[i]!=0)) {
				vc[i]++;
				rest--;
			}
			if (fabs(rest) < 1e-6)break;
		}
	}
	else if(rest<0){
		for (int i = 0; i < n; i++) {
			if (a[i] < 0&& ((int)a[i] - a[i] != 0)) {
				vc[i]--;
				rest++;
			}
			if (fabs(rest) < 1e-6)break;
		}
	}
	for (auto c : vc) {
		cout << c << endl;
	}
	return 0;
}
```

