## B. Odd Sum Segments

&nbsp;

前缀和，记元素和，若区间中元素和为正，则记下来。

最终分段数可能小于k，或大于k。若小于k则NO，大于k则到k-1后直接输出n。

```c++
#include<iostream>
#include<vector>
using namespace std;
#define ll long long
const int maxn = 2e5 + 5;
ll a[maxn];
ll sum[maxn];
int main() {
	cin.sync_with_stdio(false);
	int q;
	cin >> q;
	while (q--) {
		vector<int>ans;
		bool ok = 0;
		int n, k;
		cin >> n >> k;
		for (int i = 1; i <= n; i++) {
			cin >> a[i];
			sum[i] = sum[i - 1] + a[i];
			if (sum[i] % 2 == 1)ok = 1;
		}
		if ((k % 2 == 0 && sum[n] % 2 == 1) || (k % 2 == 1 && sum[n] % 2 == 0)) {
			cout << "NO" << endl;
			continue;
		}
		int st = 0;
		for (int i = 1; i <= n; i++) {
			if ((sum[i] - sum[st]) % 2 == 1) {
				ans.push_back(i);
				st = i;
			}
		}
		if (ans.size() < k)cout << "NO" << endl;
		else {
			cout << "YES" << endl;
			for (int i = 0; i < k - 1; i++) {
				cout << ans[i] << ' ';
			}
			cout << n << endl;
		}
	}
}
