## C. Robot Breakout

&nbsp;

每一个询问独立，不需处理。对于每个机器人，记录它能走到的x轴，y轴范围，分两个区间记录，读入一个机器人的默认位置时用该点xy坐标更新区间，若能向左，则x轴左区间扩到最负，其它类似。

如果读入一个机器人时，该机器人能到的区间与目前记录的之前所有机器人能到的区间无交集，则无答案。若有交集，则总区间更新为该交集。

```c++
#include<iostream>
#include<algorithm>
using namespace std;
#define ll long long
const int N=1e5;
int q;
bool is_cross(int x1, int y1, int x2, int y2) {
	if (x2 > y1 || x1 > y2)
		return false;
	return true;
}
int main() {
	cin.sync_with_stdio(false);
	cin >> q;
	int stX, edX, stY, edY;
	while (q--) {
		int n;
		cin >> n;
		stX = -N, edX = N;
		stY = -N, edY = N;
		bool flg = true;
		for (int i = 0; i < n; i++) {
			int x, y;
			int f1, f2, f3, f4;
			cin >> x >> y >> f1 >> f2 >> f3 >> f4;
			int stx = x, edx = x;
			int sty = y, edy = y;
			if (f1) {
				stx = -N;
			}
			if (f2) {
				edy = N;
			}
			if (f3) {
				edx = N;
			}
			if (f4) {
				sty = -N;
			}
			if (!is_cross(stX, edX, stx, edx) || !is_cross(stY, edY, sty, edy)) {
				flg = false;
			}
			else {
				stX = max(stX, stx);
				edX = min(edX, edx);
				stY = max(stY, sty);
				edY = min(edY, edy);
			}
		}
		if (!flg)cout << 0 << endl;
		else {
			cout << 1 << ' ' << stX << ' ' << stY << endl;
		}
	}
	return 0;
}
```

