int nxt[maxn];
void getNextVal(string p) {
	int plen = p.length();
	nxt[0] = -1;
	int k = -1;
	int j = 0;
	while (j < plen) {
		if (k == -1 || p[j] == p[k]) {
			j++;
			k++;
			if (p[j] != p[k]) {
				nxt[j] = k;
			}
			else{
				nxt[j] = nxt[k];
			}
		}
		else { 
			k = nxt[k];
		}
	}
}
int kmp(string s, string p) { //总串s，模式串p
	int i = 0, j = 0;
	getNextVal(p);
	int slen = s.length();
	int plen = p.length();
	while (i < slen&&j < plen) {
		if (j == -1 || s[i] == p[j]) {
			i++;
			j++;
		}
		else {
			j = nxt[j];
		}
	}
	if (j == plen) {
		return i - j;
	}
	else {
		return -1;
	}
}
