## B. The least round way

&nbsp;

maze中的数大于等于0，等于0时是特殊情况。

只有在相乘的数中有因数2，5才会产生乘积末尾的0，因此因数2，5的个数是影响因素。

则我们记录每个数字包含2，5的个数，分开记录。

考虑一下，一条路径上最终乘积中末尾0的个数一定等于路径上包含因数2与因数5中小的那个。即**cnt(10)=min(cnt(2),cnt(5))**。所以我们要找的就是包含因数2最少的路径与包含因数5最少的路径，并比较两者，取小的那个。

至于输出路径，同样是分开记录2和5，path[i] [j]记录坐标(i,j)的前一个坐标，(i,j)的父节点，最后递归输出。

以上是maze中不含0的情况，若maze中含0，则比较以上得到的结果ans是否大于1，若大于1，则还不如直接经过0。所以若ans大于1，只要找到任意一条经过0的路径输出即可。

```c++
#include<iostream>
#include<algorithm>
#include<cstring>
using namespace std;
const int maxn = 1005;
int n;
int maze[maxn][maxn][2];
int dp[maxn][maxn][2];
int path[2][maxn][maxn][2];
int num_2(int x) {
	int res = 0;
	while (x%2==0) {
		x = x / 2;
		res++;
	}
	return res;
}
int num_5(int x) {
	int res = 0;
	while (x % 5 == 0) {
		x = x / 5;
		res++;
	}
	return res;
}
void print(int k, int i, int j) {
	if (i == 1 && j == 1) {
		return;
	}
	int x = path[k][i][j][0], y = path[k][i][j][1];
	print(k, x, y);
	if (x == i - 1)cout << 'D';
	else cout << 'R';
}
int main() {
	cin.sync_with_stdio(false);
	int a = -1, b = -1;
	cin >> n;
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= n; j++) {
			int tp;
			cin >> tp;
			if (tp == 0) {
				a = i, b = j;
				continue;
			}
			maze[i][j][0] = num_2(tp);//0记录因数2
			maze[i][j][1] = num_5(tp);//1记录因数5，下同
		}
	}
	memset(dp, 0x3f3f3f3f, sizeof(dp));
	dp[1][1][0] = maze[1][1][0];
	dp[1][1][1] = maze[1][1][1];
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= n; j++) {
			for (int k = 0; k <= 1; k++) {
				if (i > 1 && dp[i][j][k] > dp[i - 1][j][k] + maze[i][j][k]) {
					dp[i][j][k] = dp[i - 1][j][k] + maze[i][j][k];
					path[k][i][j][0] = i - 1; path[k][i][j][1] = j;
				}
				if (j > 1 && dp[i][j][k] > dp[i][j - 1][k] + maze[i][j][k]) {
					dp[i][j][k] = dp[i][j - 1][k] + maze[i][j][k];
					path[k][i][j][0] = i; path[k][i][j][1] = j - 1;
				}
			}
		}
	}
	int ans = min(dp[n][n][0], dp[n][n][1]);
	if (ans > 1 && a != -1 && b != -1) {
		cout << 1 << endl;
		for (int i = 1; i < a; i++) {
			cout << 'D';
		}
		for (int i = 1; i < n; i++) {
			cout << 'R';
		}
		for (int i = a; i < n; i++) {
			cout << 'D';
		}
	}
	else {
		cout << ans << endl;
		if (dp[n][n][0] < dp[n][n][1]) {
			print(0, n, n);
		}
		else
		{
			print(1, n, n);
		}
	}
	return 0;
}
```

