## C. A Simple Task

&nbsp;

**状态压缩DP**

对于一个集合，若新加入的点等于该集合的起始点，则出现了环。

**注意：**

- 由于未设置访问标记，故有1->2->1的情况，ans应减去边数。

- 同样，由于无访问标记，同一个环1->2->3->1，1->3->2->1，会被正反计算，计算两次，故ans还应除2.

```c++
#include<iostream>
using namespace std;
#define ll long long
int G[20][20];
ll n, m, ans;
ll lowest(ll s) {
	int t = (s&-s);
	ll res = 1;
	while ((t & 1) == 0) {
		t =t>>1;
		res++;
	}
	return res;
}
ll dp[(1 << 20)][20];
int main() {
	cin >> n >> m;
	for (int i = 0; i < m; i++) {
		int u, v;
		cin >> u >> v;
		G[u][v] = G[v][u] = 1;
	}
	for (int i = 1; i <= n; i++) {
		dp[(1 << (i - 1))][i] = 1;
	}
	ll mx = (1 << n) - 1;
	for (ll s = 1; s <= mx; s++) {
		for (int now = 1; now <= n; now++) {
			if (dp[s][now] == 0)continue;
			ll st = lowest(s);
			for (int nex = st; nex <= n; nex++) {
				if ((now != nex) && G[now][nex]) {
					if ((s&(1 << (nex - 1)) && (nex == st))) {
						ans += dp[s][now];
					}
					else if (!(s&(1 << (nex - 1)))) {
						ll ss = s | (1 << (nex - 1));
						dp[ss][nex] += dp[s][now];
					}
				}
			}
		}
	}
	ans -= m;
	ans /= 2;
	cout << ans << endl;
	return 0;
}
```

