## E. Choosing Capital for Treeland

&nbsp;

**树形DP**，一边深搜一边记录

两个DFS函数，dfs1(i)记录以 i 为根时，要改变的边数；dfs2(i)记录以 i 为首都时要改变的边数，即答案集合。注意这两者是不同的！！

dfs1(root,-1)是因为要将图转化为树，以便进行树形DP；dfs2(root,-1)才是产生最终答案集合。

dfs1的结果中只有dp[root]有用，作为下一步从根到叶更新的基础；dfs2的结果中所有都有用。

```c++
#include<iostream>
#include<vector>
using namespace std;
const int maxn = 2e5 + 5;
int n, dp[maxn], ans[maxn];
struct Edge
{
	int to;
	int is_pos;
};
vector<Edge>e[maxn];
void add_edge(int u, int v) {
	e[u].push_back({ v,1 });
	e[v].push_back({ u,0 });
}
void dfs1(int now, int pre) {
	for (int i = 0; i < e[now].size(); i++) {
		int to = e[now][i].to;
		int flg = e[now][i].is_pos;
		if (to == pre)
			continue;
		dfs1(to, now);
		if (flg == 1)dp[now] += dp[to];
		else dp[now] += (dp[to] + 1);
	}
}
void dfs2(int now, int pre) {
	for (int i = 0; i < e[now].size(); i++) {
		int to = e[now][i].to;
		int flg = e[now][i].is_pos;
		if (to == pre)
			continue;
		if (flg == 1)ans[to] = ans[now] + 1;
		else ans[to] = ans[now] - 1;
		dfs2(to, now);
	}
}
int main() {
	cin.sync_with_stdio(false);
	cin >> n;
	for (int i = 0; i < n - 1; i++) {
		int u, v;
		cin >> u >> v;
		add_edge(u, v);
	}
	int root = 1; //规定以root为根，可以改变root，只要在n范围内
	dfs1(root, -1);//从下到上更新
	ans[root] = dp[root];
	dfs2(root, -1);//从上到下更新
	vector<int>res;
	int min = 0x3f3f3f3f;
	for (int i = 1; i <= n; i++) {
		if (ans[i] < min) {
			min = ans[i];
			res.clear();
			res.push_back(i);
		}
		else if (ans[i] == min)
			res.push_back(i);
	}
	cout << min << endl;
	for (auto c : res) {
		cout << c << ' ';
	}
	return 0;
}
```

