厚度为1和为2的分开记录，再分别按照宽度排序，接下来就是要确定垂直放的有几本厚度为1的，有几本厚度为2的，两层循环，1的本书，2的本书，若水平放置的总宽度小于垂直放置的总厚度，则可行，比较大小。

似乎除了开始的前缀和数组，并未用到dp，看到有一个dp答案速度更快，但没看懂。

我的答案：

```c++
#include<iostream>
#include<algorithm>
using namespace std;
const int maxn = 150;
int n;
int c1[maxn], c2[maxn];
int sum1[maxn], sum2[maxn];
int n1, n2;
int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		int a, b;
		cin >> a >> b;
		if (a == 1) {
			c1[++n1] = b;
		}
		else {
			c2[++n2] = b;
		}
	}
	sort(c1+1,c1+n1+1);
	sort(c2+1,c2+n2+1);
	for (int i = 1; i <= n1; i++) {
		sum1[i] = sum1[i - 1] + c1[i];
	}
	for (int i = 1; i <= n2; i++) {
		sum2[i] = sum2[i - 1] + c2[i];
	}
	int ans = 0x3f3f3f3f;
	for (int i = 0; i <= n1; i++) {
		for (int j = 0; j <= n2; j++) {
			int down = i + 2 * j;
			int up = sum1[n1 - i] + sum2[n2 - j];
			if (up <= down) {
				ans = min(ans, down);
			}
		}
	}
	cout << ans;
	return 0;
}
