## B. Too Easy Problems

&nbsp;

&emsp;由于本题只需要输出满足条件的一种答案，所以假设做的题目数等于最终得分数，即只做能得分的题目。

&emsp;将所有题目按照耗时从小到大排序，对要做的题目数二分查找，确定最终要做多少题目，确定题数之后，从头到尾确定做哪些题目，由于题目耗时从小到大排序，所以最后答案一定是最优。

```c++
#include<iostream>
#include<algorithm>
using namespace std;
const int maxn = 2e5 + 5;
int T, n, st, ed, times, cnt;
struct Node
{
	int most, time, index;
}nd[maxn];
bool cmp(Node a, Node b) {
	return a.time < b.time;
}
int main() {
	ios::sync_with_stdio(false);
	scanf("%d%d", &n, &T);
	for (int i = 1; i <= n; i++) {
		scanf("%d%d", &nd[i].most, &nd[i].time);
		nd[i].index = i;
	}
	sort(nd + 1, nd + n + 1, cmp);
	st = 0, ed = n;
	while (st < ed) {
		int md = (ed + st + 1) >> 1;
		cnt = 0, times = 0;
		for (int i = 1; i <= n; i++) {
			if (nd[i].most >= md) {
				if (times + nd[i].time <= T) {
					times += nd[i].time, cnt++;
				}
				else break;
			}
		}
		if (cnt >= md) {
			st = md;
		}
		else ed = md - 1;
	}
	printf("%d\n%d\n", st, st);
	cnt = 0;
	for (int i = 1; i <= n&&cnt < st; i++) {
		if (nd[i].most >= st) { printf("%d ",nd[i].index); cnt++; }
	}
	return 0;
}
