## E. Interesting Array

&nbsp;

&emsp;线段树，差分

&emsp;先根据所有条件构造答案数组，再用答案数组比对每一个询问，若有不符合的，输出NO。

```c++
#include<iostream>
using namespace std;
#define lson l,mid,2*id
#define rson mid+1,r,2*id+1
const int maxn = 150000;
struct Node
{
	int l, r, val;
}que[maxn];
int INF ;
int tree[maxn*4];
int a[maxn];	//构造出的数组
int n, m;
int sum[32][maxn];
int tot[32];

void push_up(int id) {
	//向上更新，树上存区间所有元素&
	tree[id] = tree[2 * id] & tree[2 * id + 1];
}
void build(int l, int r, int id) {
	//叶子上存该点数字
	if (l == r) {
		tree[id] = a[l];
		return;
	}
	int mid = (l + r) >> 1;
	build(lson);
	build(rson);
	push_up(id);//向上更新
}
int query(int L,int R,int l,int r,int id) {
	if (L <= l && R >= r) {
		return tree[id];
	}
	int ans = INF;
	int mid = (l+r) >> 1;
	if (L <= mid)ans&=query(L, R, lson);
	if (R > mid)ans&=query(L, R, rson);
	return ans;
}
int main() {
	ios::sync_with_stdio(false);
	for (int i = 0; i <= 30; i++)INF += (1 << i);
	cin >> n >> m;
	for (int i = 1; i <= m; i++)
	{
		int L, R, val;
		cin >> L >> R >> val;
		que[i].l = L; que[i].r = R, que[i].val = val;
		for (int j = 0; j <= 30; j++)
		{
			if ((val&((1 << j))) > 0)
			{	//差分数组
				sum[j][L]++;
				sum[j][R + 1]--;
			}
		}
	}
	for (int i = 1; i <= n; i++) {
		//tot存每个二进制位上是否为0
		//由于若不要求为1时，该位上可以为任意数，故不再设置tot数组为0
		int now = 0;
		for (int j = 0; j < 30; j++) {
			tot[j] += sum[j][i];
		}
		for (int j = 0; j < 30; j++) {
		//tot[j]>0说明有条件要求改二进制位上有1
			if (tot[j] > 0)now += (1 << j);
		}
		a[i] = now;
	}
	build(1, n, 1);
	for (int i = 1; i <= m; i++) {
		int val = que[i].val;
		int L = que[i].l, R = que[i].r;
		if (query(L, R, 1, n, 1) != val) {//有一个条件不符合
			cout << "NO";
			return 0;
		}
	}
	cout << "YES" << endl;
	for (int i = 1; i <= n; i++) {
		cout << a[i] << ' ';
	}
	return 0;
}
```

