void paint_1(Node* a) {
	if (color[a->index] != -1)
		return;
	len_now++;
	color[a->index] = num_color;
	for (auto c : a->neighbour) {
		if (color[c->index] == -1) {
			paint_1(c);
		}
	}
}
void paint(Node* a) {
	len_now = 0;
	paint_1(a);
	len_color[num_color] = len_now;
	num_color++;
}
bool operator<(pni a, pni b) {
	return a.second < b.second;
}
bool visited[maxn];
int find(Node* a,Node* b) {
	memset(visited, 0, N+2);
	priority_queue<pni>pr;
	pr.push(pni(a, 0));
	Node* tmp = a;
	while (!pr.empty()) {
		pni tp = pr.top();
