## K-近邻法

距离度量标准：欧式距离或更一般的 $L_p$ 距离。

k 值的选择：k 值小时，k 近邻模型更复杂；k 值大时，模型更简单（当 k=N 时，最简单）；用交叉验证法取得最合适的 k 值。

分类决策原则：多数表决。

## 构造kd树

kd树用于搜索与规定点空间距离最小的点。

kd树与线段树类似，线段树存某一区间，kd树存某一k维空间。

构造kd树的方法也是从一整个空间开始，递归往下分配空间。

**每个节点存其所在维度，父子节点，以便之后搜索。**

```C++
#include<iostream>
#include<algorithm>
#include<vector>
using namespace std;
const int k = 2;		//k维度
const int maxn = 100;		//最大节点数
int cmp_dim;			//排序时的维度
vector<vector<int> >dat;	//存节点坐标
struct Node {			//节点
	int value[k];			//坐标
	int dim;			//节点所在维度
	Node* parant=NULL;
	Node* left_ch=NULL;	//父节点，子节点
	Node* right_ch=NULL;
}kdnode[maxn];
bool cmp(const Node& a,const Node& b) {
	return a.value[cmp_dim] < b.value[cmp_dim];
}

Node* build(int l,int r,int d) {
	if (l > r)return NULL;
	int m;
	cmp_dim = d;
	if ((l + r) & 1)m = 1+(l + r) >> 1;	//中位点
	else m = (l + r) >> 1;
	nth_element(kdnode + l, kdnode + m, kdnode + r + 1,cmp);
	kdnode[m].dim = d;
	 Node* lch = build(l, m-1, (d + 1) % k);	//递归建树
	if(lch!=NULL)
		lch->parant = kdnode + m;
	Node* rch = build(m + 1, r, (d + 1) % k);
	if(rch!=NULL)
		rch->parant = kdnode + m;
	return kdnode + m;

}

int main() {
	int n = 6;
	dat.push_back({ 2,3 });
	dat.push_back({ 5,4 });
	dat.push_back({ 9,6 });
	dat.push_back({ 4,7 });
	dat.push_back({ 8,1 });
	dat.push_back({ 7,2 });
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < k; j++) {
			kdnode[i].value[j] = dat[i][j];
		}
	}
	build(0, n - 1, 0);

	return 0;
}
```

## 搜索kd树

1. 找到包含目标点的叶节点
2. 以此节点为当前最近节点
3. 向上回退。同时检查：

   1. 若父节点更近，更新；

   2. 若兄弟节点空间可能存在更近的点（到轴距离小于当前最小距离），检查兄弟节点。
4. 当回到根节点，搜索结束。最终最近节点即为结果。

所有代码：

```c++
#include<iostream>
#include<algorithm>
#include<vector>
#include<cmath>
using namespace std;
const int k = 2;		//k维度
const int maxn = 100;		//最大节点数
int cmp_dim;			//排序时的维度
vector<vector<int> >dat;	//存节点坐标
struct Node {			//节点
	int value[k];			//坐标
	int dim;			//节点所在维度
	Node* parent=NULL;
	Node* left_ch=NULL;	//父节点，子节点
	Node* right_ch=NULL;
}kdnode[maxn];
bool cmp(const Node& a,const Node& b) {
	return a.value[cmp_dim] < b.value[cmp_dim];
}

Node* build(int l,int r,int d) {
	if (l > r)return NULL;
	int m;
	cmp_dim = d;
	if ((l + r) & 1)m = 1+(l + r) >> 1;	//中位点
	else m = (l + r) >> 1;
	nth_element(kdnode + l, kdnode + m, kdnode + r + 1,cmp);
	kdnode[m].dim = d;
	 Node* lch = build(l, m-1, (d + 1) % k);	//递归建树
	 if (lch != NULL)
	 {
		 lch->parent = kdnode + m;
		 kdnode[m].left_ch = lch;
	 }
	Node* rch = build(m + 1, r, (d + 1) % k);
	if (rch != NULL)
	{
		rch->parent = kdnode + m;
		kdnode[m].right_ch = rch;
	}
	return kdnode + m;

}

//distance返回欧式距离的平方
int distance(int* a,int* b) {
	int res = 0;
	for (int i = 0; i < k; i++)
		res += (a[i]-b[i])*(a[i]-b[i]);
	return res;
}

Node* root;			//kd树的根
int min_dis;			//最近点与目标点距离
Node* nearest;		//最近点

//找到包含目标点的叶节点
Node* the_one(int* arr) {
	int d = 0;
	Node* r=root;
	Node* tmp=r;
	while (r != NULL) {
		tmp = r;
		if (r->value[d] > arr[d]) {
			r = r->left_ch;
		}
		else
			r = r->right_ch;
		d = (d + 1) % k;
	}
	min_dis = distance(arr, tmp->value);
	nearest = tmp;
	return tmp;
}
//在某一节点 从上往下 找最近点
void search_son(Node* son, int* tar) {
	if (son == NULL)
		return;
	if (distance(son->value, tar) < min_dis) {	//如果当前点更近，则更新
		nearest = son;
		min_dis = distance(son->value, tar);
	}
	//若轴与目标点距离小于当前最小距离，则两边都要找
	if (pow(son->value[son->dim] - tar[son->dim], 2) < min_dis) {
		search_son(son->left_ch, tar);
		search_son(son->right_ch, tar);
	}
	//只要找一边
	else {
		//目标点在轴左边，找左边空间
		if (son->value[son->dim] > tar[son->dim])
			search_son(son->left_ch, tar);
		else
			search_son(son->right_ch, tar);
	}
}

//在某一点 从下往上 找最近点
void search_all(Node* now,int tar[k]) {
	Node* par = now->parent;
	while (now->parent != NULL) {
		now = now->parent;
		//若父节点更近，则更新
		if (distance(tar, now->value) < min_dis) {
			nearest = now;
			min_dis = distance(tar, now->value);
		}
		Node* son;
		//若轴与目标点距离小于当前最小距离，还要在另一边找
		if (pow(now->value[now->dim], 2) < min_dis) {
			//目标点在轴右边，找右边空间
			if (now->value[now->dim] > tar[now->dim])
				son = now->right_ch;
			else
				son = now->left_ch;
			//确定在哪边空间后，从上往下找
			search_son(son,tar);
		}
	}
}
int main() {
	int n = 6;
	dat.push_back({ 2,3 });
	dat.push_back({ 5,4 });
	dat.push_back({ 9,6 });
	dat.push_back({ 4,7 });
	dat.push_back({ 8,1 });
	dat.push_back({ 7,2 });
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < k; j++) {
			kdnode[i].value[j] = dat[i][j];
		}
	}
	root=build(0, n - 1, 0);
	//测试
	int a[2] = { 8,2 };
	Node* now = the_one(a);
	search_all(now, a);
	//distance返回的是最小距离的平方，结果还应开根号
	cout << distance(nearest->value, a);
	return 0;
}
```

## 特征选择

1. ### 信息增益

   1.1 熵

   ​	随机变量 X ，其分布概率为 $P(X=x_i)=p_i , i=1,2,\cdots,n$

   ​	熵定义为 :

   ​	$$H(X)=-\sum_{i=1}^np_i\log {p_i}$$

   ​	若$p_i=0$ ，则定义 $0\log 0=0$



   1.2 条件熵

   ​	随机变量 Y 在 X 条件下的熵。

   ​	定义为：X 给定的条件下，Y 的条件概率分布的熵对 X 的数学期望。

   ​	$H(Y|X)=\sum_{i=1}^n p_iH(Y|X=x_i)$



   1.3 信息增益

   ​	已知特征 X 而使 Y 的不确定性减少的程度。

   ​	$g(D,A)=H(D)-H(D|A)$

   ​	$D$ 表示输入空间，$A$表示特征。



2. ### ID3算法

   2.1 算法

   ​	(1) 若 D 中所有实例属于同一类 $C_k$，则 T 为单节点树，将 $C_k$ 作为该结	点的类标记，返回 T ；

   ​	(2) 若 $A =\varnothing$.  则 T 为单节点树，将 D 中包含实例数最大的类 $C_k$ 作为	该结点的类标记，返回 T ；

   ​	(3) 否则，计算信息增益，选择信息增益最大的特征 $A_g$ ；

   ​	(4) 如果 $A_g$ 的信息增益小于设定的阈值 $\varepsilon$ ，则置 T 为单节点树，将 D 	中包含实例数最大的类 $C_k$ 作为该结点的类标记，返回 T ；

   ​	(5) 否则，对$ A_g$ 每个可能的选择将 D 分为若干个子集，以其包含实例数	最大的 $C_k$ 作为该结点的类标记；构建子节点。

   ​	(6) 对第 i 个子节点，以 $D_i$ 为数据集，以 $A-{A_g}$ 为特征集，递归调用 	(1)~(5)，得到子树 $T_i$ ，返回 $T_i$ 。



   2.2 代码

   ```c++
   #include<iostream>
   #include<fstream>
   #include<vector>
   #include<cstring>
   #include<cmath>
   #include<algorithm>
   using namespace std;
   const int maxn = 100;	//最大数据数
   const int maxk = 100;	//特征最大种类数
   int K;
   vector<vector<int> >dat;	//初始输入空间
   vector<int>character;		//初始特征空间

   double log_2(double a) {	//以2为底log
   	if (a == 0)return 0.0;
   	return log(a) / log(2);
   }
   struct Node {
   	vector<Node*>child;
   	int num_char = 0;
   	vector<vector<int> >val;
   	vector<int>cha;
   	int label = 0;
   	Node() {};
   	Node(vector<vector<int> > a,vector<int> b):val(a),cha(b) {};
   };

   double comput_pd(vector<vector<int> >arr) {			//计算P(D)
   	int N_now = 0;
   	int tot = 0;
   	for (auto c:arr) {
   		N_now++;
   		tot += c[K];
   	}
   	double res = -(1.0*tot/N_now)*log_2(1.0*tot / N_now)-(1.0*(N_now-tot)/N_now)*log_2(1.0*(N_now - tot) / N_now);
   	return res;
   }
   double compute_pda(int chara,vector<vector<int> >arr) {	//计算P(D|Ai),第chara个特征
   	double res=0;
   	vector<vector<int> >p[maxk];
   	vector<int>cnt;
   	int N_now=0;
   	for (int i = 0; i < character[chara]; i++)
   		cnt.push_back(0);
   	for (auto c : arr) {
   		N_now++;
   		p[c[chara]].push_back(c);
   		cnt[c[chara]]++;
   	}
   	for (int i = 0; i < character[chara]; i++) {
   		res += (cnt[i] * 1.0 / N_now)*comput_pd(p[i]);
   	}
   	return res;
   }
   double compute(int chara,vector<vector<int> >arr) {
   	return comput_pd(arr) - compute_pda(chara,arr);
   }
   int find_most(const vector<vector<int> >& arr) {	//找到包含实例最多的类
   	int a = 0;
   	int b = 0;
   	for (auto c : arr) {
   		if (c[K] == 1)
   			a++;
   		else b++;
   	}
   	return a > b ? 1 : 0;
   }

   Node* build(const vector<vector<int> >& arr,const vector<int>& car) {//建树
   	Node* t = new Node;
   	t->cha = car;
   	t->val = arr;
   	int a = 0;
   	int b = 0;
   	for (auto c : t->val) {
   		if (c[K] == 1)a++;
   		else b++;
   	}
   	if (a == 0 ) {				//数据类别单一
   		t->label = 0;
   		return t;
   	}
   	if (b == 0) {
   		t->label = 1;
   		return t;
   	}
   	if (t->cha.empty()) {			//特征空间为空
   		t->label = a > b ? 1 : 0;
   		return t;
   	}
   	t->label = find_most(t->val);
   	double mak = 0;
   	int tmp;
   	for (auto c:t->cha) {			//找到信息增益最大的特征
   		double a = compute(c, t->val);
   		if (a > mak) {
   			mak = a;
   			tmp = c;
   		}
   	}
   	t->num_char = tmp;
   	vector<int>ca_new;
   	for (auto c : t->cha) {				//新的特征空间
   		if (c != tmp)ca_new.push_back(c);
   	}
   	for (int i = 0; i < character[tmp]; i++) {	//新的输入空间
   		vector<vector<int> >at;
   		for (auto c : t->val) {
   			if (c[tmp]==i)
   				at.push_back(c);
   		}
   		t->child.push_back(build(at,ca_new));
   	}
   	return t;
   }
   //搜索决策树
   int search(vector<int>arr, Node* root) {
   	if (root->child.empty()) {
   		return root->label;
   	}
   	int next_ch = arr[root->num_char];
   	return search(arr, root->child[next_ch]);
   }

   int main() {
   	ifstream fin;
   	fin.open("train.txt");
   	K = 4;						//特征数
   	while (!fin.eof()) {
   		vector<int>tmp;
   		for (int i = 0; i <= K; i++) {
   			int _a;
   			fin >> _a;
   			tmp.push_back(_a);	//初始输入空间
   		}
   		dat.push_back(tmp);
   	}
   	fin.close();
   	vector<int>cara;
   	character.push_back(3); character.push_back(2); character.push_back(2); character.push_back(3);
   	for (int i = 0; i < K; i++)
   		cara.push_back(i);		//初始特征空间
   	Node* root=build(dat,cara);

   	//test
   	vector<int>test;
   	test.push_back(2); test.push_back(1); test.push_back(0); test.push_back(1);
   	cout<<search(test, root);
   	return 0;
   }
