```python
import numpy as np
import requests

def get_data(url):
    content=requests.get(url).content
    content=content.decode('utf-8')
    content=content.split("\n")
    X=[]
    Y=[]
    for line in content[:-1]:
        data=line.split()
        y=float(data[-1])
        Y.append(y)
        x=data[:-1]
        for i in range(len(x)):
            x[i]=float(x[i])
        X.append([1.0]+x)
    X=np.mat(X)
    Y=np.array(Y)
    return X,Y

def init(X):
    return np.zeros((X.shape[1],1))

def sigmoid(s):
    return 1/(1+np.exp(-s))


def grad(w,X,Y,i):
    s=-Y[i]*X[i]*w
    return -Y[i]*sigmoid(s).item()*X[i].T

def sign(v):
    if v>=0.5:
        return 1
    else:
        return -1
def cost(w,X,Y):
    err=0
    y_hat=sigmoid(X*w).T
    y_hat=y_hat.tolist()
    for i in range(len(Y)):
        if(sign(y_hat[0][i])!=Y[i]):
            err+=1
    return err/len(Y)

if __name__=="__main__":
    trainX,trainY=get_data("https://www.csie.ntu.edu.tw/~htlin/mooc/datasets/mlfound_algo/hw3_train.dat")
    testX,testY=get_data("https://www.csie.ntu.edu.tw/~htlin/mooc/datasets/mlfound_algo/hw3_test.dat")
    w=init(trainX)
    l_r=0.01
    for i in range(2000):
        w=w-l_r*grad(w,trainX,trainY,i%len(trainY))
    print(cost(w,testX,testY))
```

# 拓扑序

**有向无环图**DAG，对每一个顶点给一个编号，第i号顶点叫做v，那么存在顶点 v~i~ 到顶点<kbd>v~j~</kbd>的边时，就有**i<j**成立，这样的编号方式叫做**拓扑序**。
<!--more-->
## 拓扑排序
 ![在这里插入图片描述](https://img-blog.csdnimg.cn/20190331155113375.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3dlaXhpbl80Mzk0ODYzOA==,size_16,color_FFFFFF,t_70)
如果把图（a）中的顶点按照拓扑序从右到左排列，那么所有的边都是从左指向右的。求解拓扑序的算法叫做**拓扑排序**。
### DFS算法
***使用栈以使结果为正向排序，由于每个顶点和每条边都只访问了一次，因此复杂度时O(|V|+|E|).***
#### 已知为DAG的情况
对每一个节点设置属性visited为0或1，未访问过为0，访问过为1.
`dfs(u)`其中n为节点，不断深入递归，当其所有子节点都已被访问过之后才会退出。
所以可以知道最先被访问的必定是拓扑序最大的，则先将其`push`至栈中，最后从栈中取出时即为正序。

```c
#include <iostream>
#include <stack>
using namespace std;

struct Edge {
    int to, next;
};

const int maxn = 10010;
int head[maxn] = {};
int n, m, cnt = 1;
bool vis[maxn] = {};
Edge edge[maxn];
stack<int> S;

void add(int u, int v)
{
    edge[cnt].to = v;
    edge[cnt].next = head[u];
    head[u] = cnt++;
}

void dfs(int u)
{
    vis[u] = true;
    for (int i = head[u]; i; i = edge[i].next) {
        int v = edge[i].to;
        if (!vis[v]) dfs(v);
    }
    S.push(u);
}

int main()
{
    cin >> n >> m;
    for (int i = 1; i <= m; ++i) {
        int u, v;
        cin >> u >> v;
        add(u, v);
    }
    for (int i = 1; i <= n; ++i) {
        if (vis[i] == 0) dfs(i);
    }
    while (!S.empty()) {
        cout << S.top() << ' ';
        S.pop();
    }
}
```

#### 判环
那么，如何判环呢？判环只是在`dfs`函数上稍做些修改，其中最主要的是`vis`数组的含义有所扩展，以及对下一结点进行`dfs`的条件判断。

不判环的拓扑排序，`vis`只代表某一结点有没有被放问过，而现在，`vis`有三个值，-1，0，1。
**-1**代表已访问过，但不是从当前系列`dfs`访问来的，**0**代表未访问过，**1**代表访问过，且是当前系列访问过的（意味着有环，如`u->v`,` v->t`,` t->u`）

```c++
bool dfs(int u)
{
    vis[u] = 1;
    for (int i = head[u]; i; i = edge[i].next) {
        int v = edge[i].to;
        if (vis[v] == 1) return false;
        if (vis[v] == 0 && !dfs(v)) return false;
    }
    vis[u] = -1;
    S.push(u);
    return true;
}
```

### Kahn算法
**其实就是不断的寻找有向图中没有前驱(入度为0)的顶点，将之输出。然后从有向图中删除所有以此顶点为尾的弧。重复操作，直至图空，或者找不到没有前驱的顶点为止。**

**该算法还可以判断有向图是否存在环(存在环的有向图肯定没有拓扑序列)，通过一个count记录找出的顶点个数，如果少于N则说明存在环使剩余的顶点的入度不为0。（degree数组记录每个点的入度数）**

```c++
#include <bits/stdc++.h>
using namespace std;
const int maxn = 505;
struct node
{
	int v, next;
}edge[maxn*maxn];
int degree[maxn], head[maxn];
queue<int> q;
list<int> ans; 
int n, m, no;
inline void init()
{
	no = 0;
	while(!q.empty()) q.pop();
	memset(degree, 0, sizeof degree);
	memset(head, -1, sizeof head);
}
inline void add(int u, int v)
{
	edge[no].v = v;
	edge[no].next = head[u];
	head[u] = no++;
}
int Kahn()
{
	int count = 0;
	while(!q.empty())
	{
		int tp = q.front(); q.pop();
		++count; ans.push_back(tp);	//加入链表中，加入数组或者vector或者queue都无所谓 
		int k = head[tp];
		while(k != -1)
		{
			--degree[edge[k].v];
			if(!degree[edge[k].v]) q.push(edge[k].v);
			k = edge[k].next;
		}
	}
	if(count == n) return 1;
	return 0;
}
int main()
{
	int u, v;
	scanf("%d %d", &n, &m); init();
	for(int i = 1; i <= m; ++i)
	{
		scanf("%d %d", &u, &v);
		add(u, v); ++degree[v];
	}
	for(int i = 1; i <= n; ++i)
	{
		if(!degree[i]) q.push(i);
	}
	Kahn();
	list<int>::iterator it;
	for(it = ans.begin(); it != ans.end(); ++it)
	{
		cout << *it << " ";
	}
	cout << endl;
	return 0;
}
```

